1	// User input processing and drag-to-swap mechanics
2	
3	import {
4	    getTileValue,
5	    createTile,
6	    createJokerTile,
7	    isBlocked,
8	    isBlockedWithLife,
9	    isBlockedMovable,
10	    isBlockedWithMergeCount,
11	    isRectangularBlocked,
12	    isJoker,
13	    isTileFreeSwapTile,
14	    isTileStickyFreeSwapTile,
15	    isTileFreeSwapHorizontalTile,
16	    isTileFreeSwapVerticalTile,
17	    isTileHammerTile,
18	    isTileHalverTile,
19	    isTileTeleportTile,
20	    isWildTeleportTile,
21	    getDisplayValue,
22	    findBestJokerValue,
23	    getUniqueTileValues,
24	} from "./tile-helpers.js";
25	import { track } from "./tracker.js";
26	import { getMatchTilesForSwap } from "./hint-system.js";
27	import {
28	    isTutorialActive,
29	    isValidTutorialSwap,
30	    advanceTutorialStep,
31	    canDragTileInTutorial,
32	    isTutorialTapStep,
33	    isValidTutorialTap,
34	    isTutorialPowerUpStep,
35	    isValidTutorialPowerUp,
36	    isValidTutorialPowerUpTarget,
37	    updateTutorialUI,
38	} from "./tutorial.js";
39	
40	export function setupEventListeners(game) {
41	    const gameBoard = document.getElementById("gameBoard");
42	
43	    // Touch events for mobile
44	    gameBoard.addEventListener("touchstart", handleTouchStart.bind(game), { passive: false });
45	    gameBoard.addEventListener("touchmove", handleTouchMove.bind(game), { passive: false });
46	    gameBoard.addEventListener("touchend", handleTouchEnd.bind(game), { passive: false });
47	
48	    // Mouse events for desktop
49	    gameBoard.addEventListener("mousedown", handleMouseDown.bind(game));
50	    gameBoard.addEventListener("mousemove", handleMouseMove.bind(game));
51	    gameBoard.addEventListener("mouseup", handleMouseUp.bind(game));
52	    gameBoard.addEventListener("mouseleave", handleMouseUp.bind(game));
53	}
54	
55	function handleTouchStart(e) {
56	    e.preventDefault();
57	    const touch = e.touches[0];
58	    startDrag(this, touch.clientX, touch.clientY);
59	}
60	
61	function handleTouchMove(e) {
62	    e.preventDefault();
63	    const touch = e.touches[0];
64	    updateDrag(this, touch.clientX, touch.clientY);
65	}
66	
67	function handleTouchEnd(e) {
68	    e.preventDefault();
69	    endDrag(this);
70	}
71	
72	function handleMouseDown(e) {
73	    startDrag(this, e.clientX, e.clientY);
74	}
75	
76	function handleMouseMove(e) {
77	    updateDrag(this, e.clientX, e.clientY);
78	}
79	
80	function handleMouseUp() {
81	    endDrag(this);
82	}
83	
84	function startDrag(game, x, y) {
85	    if (!game.gameActive) return;
86	
87	    // Clear hint on user interaction (don't start timer until drag ends)
88	    game.clearHint();
89	    game.clearHintTimer();
90	
91	    const element = document.elementFromPoint(x, y);
92	    if (element && element.classList.contains("gem")) {
93	        const row = parseInt(element.dataset.row);
94	        const col = parseInt(element.dataset.col);
95	        const tile = game.board[row][col];
96	
97	        // Block dragging tiles during tutorial if not part of the tutorial step
98	        if (isTutorialActive(game) && !canDragTileInTutorial(game, row, col)) {
99	            return;
100	        }
101	
102	        // Handle power-ups (but not during animations)
103	        if (game.activePowerUp) {
104	            // Prevent power-up usage during animations
105	            if (game.animating) return;
106	
107	            // Check tutorial validation for power-up usage
108	            if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
109	                // Only allow clicking on the specified tutorial target
110	                if (!isValidTutorialPowerUpTarget(game, row, col)) {
111	                    return; // Block usage on wrong tile
112	                }
113	            }
114	
115	            const handled = game.handlePowerUpAction(row, col, element);
116	            if (handled !== false) {
117	                // If power-up was used successfully, advance tutorial
118	                if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
119	                    advanceTutorialStep(game);
120	                }
121	                return;
122	            }
123	            // If handlePowerUpAction returns false (swap case), continue with normal drag
124	        }
125	
126	        if (isBlockedWithLife(tile) || isBlockedMovable(tile) || isRectangularBlocked(tile)) {
127	            return;
128	        }
129	        if (isBlocked(tile) && game.activePowerUp !== "swap") {
130	            return;
131	        }
132	
133	        // Normal drag behavior (including joker)
134	        game.selectedGem = {
135	            element: element,
136	            row: row,
137	            col: col,
138	            tile: tile, // Store tile to detect joker taps later
139	        };
140	        game.isDragging = true;
141	        game.dragStartPos = { x, y };
142	        game.dragStartTime = performance.now();
143	        game.lastPreviewTile = null;
144	        game.wasInAdjacentZone = true;
145	        element.classList.add("dragging");
146	        showValidSwapTargets(game, row, col);
147	    }
148	}
149	
150	function updateDrag(game, x, y) {
151	    if (!game.isDragging || !game.selectedGem) return;
152	
153	    const element = document.elementFromPoint(x, y);
154	    if (!element || !element.classList.contains("gem")) return;
155	
156	    const sourceRow = game.selectedGem.row;
157	    const sourceCol = game.selectedGem.col;
158	
159	    // If user drags back to the original tile, cancel the preview
160	    if (element === game.selectedGem.element) {
161	        updatePreviewState(game, sourceRow, sourceCol, null, null);
162	        game.lastPreviewTile = null;
163	        game.wasInAdjacentZone = true;
164	        return;
165	    }
166	
167	    const targetRow = parseInt(element.dataset.row);
168	    const targetCol = parseInt(element.dataset.col);
169	
170	    // Detent: fire once when drag crosses out of the 1-tile radius on a
171	    // far-swap-capable tile. Teaches the boundary proprioceptively.
172	    if (isFarSwapCapable(game.selectedGem.tile)) {
173	        const manhattan = Math.abs(targetRow - sourceRow) + Math.abs(targetCol - sourceCol);
174	        const inAdjacentZone = manhattan <= 1;
175	        if (game.wasInAdjacentZone && !inAdjacentZone) {
176	            triggerDetentPulse(element);
177	        }
178	        game.wasInAdjacentZone = inAdjacentZone;
179	    }
180	
181	    // Check if gems are adjacent or allowed by extended free swap rules
182	    if (canPreviewSwap(game, sourceRow, sourceCol, targetRow, targetCol)) {
183	        const last = game.lastPreviewTile;
184	        if (!last || last.row !== targetRow || last.col !== targetCol) {
185	            game.lastPreviewTile = { row: targetRow, col: targetCol };
186	        }
187	        updatePreviewState(game, sourceRow, sourceCol, targetRow, targetCol);
188	    }
189	}
190	
191	function isFarSwapCapable(tile) {
192	    return (
193	        isTileTeleportTile(tile) ||
194	        isWildTeleportTile(tile) ||
195	        isTileFreeSwapTile(tile) ||
196	        isTileStickyFreeSwapTile(tile) ||
197	        isTileFreeSwapHorizontalTile(tile) ||
198	        isTileFreeSwapVerticalTile(tile)
199	    );
200	}
201	
202	function triggerDetentPulse(element) {
203	    element.classList.remove("detent-crossed");
204	    void element.offsetWidth; // force reflow to restart animation
205	    element.classList.add("detent-crossed");
206	    setTimeout(() => element.classList.remove("detent-crossed"), 260);
207	}
208	
209	function endDrag(game) {
210	    if (!game.isDragging || !game.selectedGem) return;
211	
212	    const previewGems = document.querySelectorAll(".gem.preview");
213	
214	    if (previewGems.length > 0) {
215	        // User dragged to swap
216	        const targetGem = Array.from(previewGems).find((g) => g !== game.selectedGem.element);
217	        if (targetGem) {
218	            let targetRow = parseInt(targetGem.dataset.row);
219	            let targetCol = parseInt(targetGem.dataset.col);
220	
221	            // Velocity gate: fast flicks >1 tile away are likely 1-tile overshoots,
222	            // since users are trained on adjacent-only swaps. Snap to the adjacent
223	            // tile in the direction of release.
224	            const sr = game.selectedGem.row;
225	            const sc = game.selectedGem.col;
226	            const manhattan = Math.abs(sr - targetRow) + Math.abs(sc - targetCol);
227	            const duration = performance.now() - (game.dragStartTime ?? 0);
228	            if (manhattan > 1 && duration < FAST_FLICK_MS) {
229	                const snapped = snapToAdjacentInDirection(game, sr, sc, targetRow, targetCol);
230	                if (snapped) {
231	                    targetRow = snapped.row;
232	                    targetCol = snapped.col;
233	                }
234	            }
235	
236	            trySwap(game, sr, sc, targetRow, targetCol);
237	        }
238	    } else if (isJoker(game.selectedGem.tile) && !game.activePowerUp) {
239	        // User tapped on joker without dragging - try to activate it
240	        // Only activate if not in power-up mode
241	
242	        // Check if this is a valid tutorial tap
243	        if (isTutorialActive(game) && isTutorialTapStep(game)) {
244	            if (isValidTutorialTap(game, game.selectedGem.row, game.selectedGem.col)) {
245	                activateJokerByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
246	                // Note: Tutorial progression is handled in the joker activation callback
247	            }
248	        } else if (!isTutorialActive(game)) {
249	            activateJokerByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
250	        }
251	    } else if (isTileHammerTile(game.selectedGem.tile) && !game.activePowerUp) {
252	        // User tapped on hammer tile without dragging - activate it
253	        // Only activate if not in power-up mode
254	        activateHammerTileByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
255	    } else if (isTileHalverTile(game.selectedGem.tile) && !game.activePowerUp) {
256	        // User tapped on halver tile without dragging - activate it
257	        // Only activate if not in power-up mode
258	        activateHalverTileByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
259	    }
260	
261	    // Clean up
262	    document.querySelectorAll(".gem").forEach((gem) => {
263	        gem.classList.remove(
264	            "dragging",
265	            "preview",
266	            "merge-preview",
267	            "unblock-preview",
268	            "swap-dimmed",
269	            "detent-crossed",
270	        );
271	    });
272	
273	    // Reset hint timer after user interaction completes
274	    game.resetHintTimer();
275	
276	    game.selectedGem = null;
277	    game.isDragging = false;
278	    game.dragStartPos = null;
279	    game.dragStartTime = null;
280	    game.lastPreviewTile = null;
281	    game.wasInAdjacentZone = true;
282	}
283	
284	const FAST_FLICK_MS = 150;
285	
286	function snapToAdjacentInDirection(game, sr, sc, tr, tc) {
287	    const dr = tr - sr;
288	    const dc = tc - sc;
289	    const useRowAxis = Math.abs(dr) >= Math.abs(dc);
290	    const adjR = sr + (useRowAxis ? Math.sign(dr) : 0);
291	    const adjC = sc + (useRowAxis ? 0 : Math.sign(dc));
292	    if (adjR < 0 || adjR >= game.boardHeight || adjC < 0 || adjC >= game.boardWidth) return null;
293	    const adjTile = game.board[adjR][adjC];
294	    if (
295	        isBlocked(adjTile) ||
296	        isBlockedWithLife(adjTile) ||
297	        isBlockedMovable(adjTile) ||
298	        isRectangularBlocked(adjTile)
299	    ) {
300	        return null;
301	    }
302	    return { row: adjR, col: adjC };
303	}
304	
305	function activateJokerByTap(game, row, col, element) {
306	    // Activate joker when tapped
307	    const bestValue = findBestJokerValue(game, row, col);
308	
309	    if (bestValue !== null) {
310	        // Transform and animate
311	        game.animating = true;
312	        element.style.transform = "scale(1.2)";
313	        element.textContent = getDisplayValue(bestValue);
314	        element.className = `gem tile-${bestValue}`;
315	
316	        setTimeout(() => {
317	            element.style.transform = "scale(1)";
318	            game.board[row][col] = createTile(bestValue); // Update board
319	
320	            // Set lastSwapPosition to the joker position so other jokers connected to this one can activate
321	            game.lastSwapPosition = { row, col, movedFrom: { row, col } };
322	
323	            game.renderBoard(); // Re-render to show the updated tile
324	
325	            // Progress tutorial if this was a tap-only tutorial step
326	            if (isTutorialActive(game) && isTutorialTapStep(game)) {
327	                advanceTutorialStep(game);
328	            }
329	
330	            setTimeout(() => {
331	                game.isUserSwap = true; // Treat tap as user action
332	                game.processMatches();
333	            }, 200);
334	        }, 300);
335	    } else {
336	        // No valid match found - indicate to user with a shake animation
337	        element.style.animation = "shake 0.3s";
338	        setTimeout(() => {
339	            element.style.animation = "";
340	        }, 300);
341	    }
342	}
343	
344	function activateHammerTileByTap(game, row, col, element) {
345	    // Activate hammer tile when tapped - removes the tile
346	
347	    // Animate removal
348	    game.animating = true;
349	    element.style.transform = "scale(0.5)";
350	    element.style.opacity = "0";
351	
352	    setTimeout(() => {
353	        // Remove the tile from the board
354	        game.board[row][col] = null;
355	        game.renderBoard();
356	
357	        setTimeout(() => {
358	            // Drop tiles and process matches
359	            game.isUserSwap = true;
360	            game.dropGems();
361	        }, 200);
362	    }, 300);
363	}
364	
365	function activateHalverTileByTap(game, row, col, element) {
366	    // Activate halver tile when tapped - halves the tile's value
367	    const currentValue = getTileValue(game.board[row][col]);
368	
369	    // Can only halve if value is greater than 1
370	    if (currentValue <= 1) {
371	        // Cannot halve further - show shake animation
372	        element.style.animation = "shake 0.3s";
373	        setTimeout(() => {
374	            element.style.animation = "";
375	        }, 300);
376	        return;
377	    }
378	
379	    // Calculate new value (halve it)
380	    const newValue = currentValue - 1; // Internal value decreased by 1 (which halves the display value)
381	
382	    // Animate the change
383	    game.animating = true;
384	    element.style.transform = "scale(1.2)";
385	
386	    setTimeout(() => {
387	        element.style.transform = "scale(1)";
388	        // Update the tile to regular tile with new value (no longer a halver tile)
389	        game.board[row][col] = createTile(newValue);
390	        game.renderBoard();
391	
392	        setTimeout(() => {
393	            // Process any matches that may have been created
394	            game.isUserSwap = true;
395	            game.processMatches();
396	        }, 200);
397	    }, 300);
398	}
399	
400	function areAdjacent(row1, col1, row2, col2) {
401	    const rowDiff = Math.abs(row1 - row2);
402	    const colDiff = Math.abs(col1 - col2);
403	    return (rowDiff === 1 && colDiff === 0) || (rowDiff === 0 && colDiff === 1);
404	}
405	
406	// Single-pass update of all drag-related state classes (preview, merge-preview,
407	// unblock-preview, swap-dimmed). One DOM traversal keeps class changes atomic
408	// so the dim transition doesn't visibly stagger across tiles.
409	// Pass targetRow/targetCol = null to clear preview state (drag active, no target).
410	function updatePreviewState(game, sourceRow, sourceCol, targetRow, targetCol) {
411	    const hasTarget = targetRow != null && targetCol != null;
412	
413	    const previewKeys = new Set();
414	    let mergeKeys = new Set();
415	    let unblockKeys = new Set();
416	
417	    if (hasTarget) {
418	        previewKeys.add(`${sourceRow},${sourceCol}`);
419	        previewKeys.add(`${targetRow},${targetCol}`);
420	        const matchTiles = getMatchTilesForSwap(game, sourceRow, sourceCol, targetRow, targetCol);
421	        mergeKeys = new Set(matchTiles.map((t) => `${t.row},${t.col}`));
422	        const blockedToUnblock = getBlockedTilesForMatch(
423	            game,
424	            matchTiles,
425	            sourceRow,
426	            sourceCol,
427	            targetRow,
428	            targetCol,
429	        );
430	        unblockKeys = new Set(blockedToUnblock.map((p) => `${p.row},${p.col}`));
431	    }
432	
433	    const dimEnabled = !!game.showSwapTargets;
434	    const gems = document.querySelectorAll(".gem");
435	    for (const gem of gems) {
436	        const r = parseInt(gem.dataset.row);
437	        const c = parseInt(gem.dataset.col);
438	        if (isNaN(r) || isNaN(c)) continue;
439	        const key = `${r},${c}`;
440	
441	        const isPreview = previewKeys.has(key);
442	        const isMerge = mergeKeys.has(key);
443	        const isUnblock = unblockKeys.has(key);
444	        const isSource = r === sourceRow && c === sourceCol;
445	
446	        gem.classList.toggle("preview", isPreview);
447	        gem.classList.toggle("merge-preview", isMerge);
448	        gem.classList.toggle("unblock-preview", isUnblock);
449	
450	        let shouldDim = false;
451	        if (dimEnabled && !isPreview && !isMerge && !isUnblock && !isSource) {
452	            // Dim only tiles that can't be swapped with the source. Don't dim
453	            // other valid targets during preview — they must stay interactive
454	            // (free-swap-line tiles need to be reachable via drag).
455	            shouldDim = !canPreviewSwap(game, sourceRow, sourceCol, r, c);
456	        }
457	        gem.classList.toggle("swap-dimmed", shouldDim);
458	    }
459	}
460	
461	function showValidSwapTargets(game, row, col) {
462	    updatePreviewState(game, row, col, null, null);
463	}
464	
465	function canPreviewSwap(game, row1, col1, row2, col2) {
466	    const tile2 = game.board[row2][col2];
467	    // Blocked tiles are not valid swap targets (mirrors trySwap's guards).
468	    // Simple blocked is swappable only with the swap power-up.
469	    if (isBlockedWithLife(tile2)) return false;
470	    if (isRectangularBlocked(tile2)) return false;
471	    if (isBlocked(tile2) && game.activePowerUp !== "swap") return false;
472	
473	    if (areAdjacent(row1, col1, row2, col2)) {
474	        return true;
475	    }
476	
477	    if (game.activePowerUp === "teleport") {
478	        return true;
479	    }
480	
481	    if (isTeleportSwapAllowed(game, row1, col1, row2, col2)) {
482	        return true;
483	    }
484	
485	    return isExtendedFreeSwapAllowed(game, row1, col1, row2, col2);
486	}
487	
488	function isTeleportSwapAllowed(game, row1, col1, row2, col2) {
489	    const tile1 = game.board[row1][col1];
490	    const tile2 = game.board[row2][col2];
491	
492	    // Can't teleport to/from blocked tiles
493	    if (isBlocked(tile1) || isBlocked(tile2) || isBlockedWithLife(tile1) || isBlockedWithLife(tile2)) {
494	        return false;
495	    }
496	
497	    const isTeleport1 = (isTileTeleportTile(tile1) || isWildTeleportTile(tile1)) && !tile1.hasBeenSwapped;
498	
499	    return isTeleport1;
500	}
501	
502	function isExtendedFreeSwapAllowed(game, row1, col1, row2, col2) {
503	    if (game.extendedFreeSwap !== true) {
504	        return false;
505	    }
506	
507	    const isHorizontalSwap = row1 === row2;
508	    const isVerticalSwap = col1 === col2;
509	
510	    if (!isHorizontalSwap && !isVerticalSwap) {
511	        return false;
512	    }
513	
514	    const tile1 = game.board[row1][col1];
515	
516	    const isFreeSwap1 = (isTileFreeSwapTile(tile1) || isTileStickyFreeSwapTile(tile1)) && !tile1.hasBeenSwapped;
517	
518	    const isDirectionalFreeSwap1 =
519	        !tile1.hasBeenSwapped &&
520	        ((isTileFreeSwapHorizontalTile(tile1) && isHorizontalSwap) ||
521	            (isTileFreeSwapVerticalTile(tile1) && isVerticalSwap));
522	
523	    return isFreeSwap1 || isDirectionalFreeSwap1;
524	}
525	
526	function getBlockedTilesForMatch(game, matchTiles, row1, col1, row2, col2) {
527	    const blockedSet = new Set();
528	    const result = [];
529	
530	    for (const tile of matchTiles) {
531	        // Convert pre-swap to post-swap coordinates
532	        let checkRow = tile.row;
533	        let checkCol = tile.col;
534	        if (tile.row === row1 && tile.col === col1) {
535	            checkRow = row2;
536	            checkCol = col2;
537	        } else if (tile.row === row2 && tile.col === col2) {
538	            checkRow = row1;
539	            checkCol = col1;
540	        }
541	
542	        const adjacentPositions = [
543	            { row: checkRow - 1, col: checkCol },
544	            { row: checkRow + 1, col: checkCol },
545	            { row: checkRow, col: checkCol - 1 },
546	            { row: checkRow, col: checkCol + 1 },
547	        ];
548	
549	        for (const pos of adjacentPositions) {
550	            if (pos.row >= 0 && pos.row < game.boardHeight && pos.col >= 0 && pos.col < game.boardWidth) {
551	                const key = `${pos.row}_${pos.col}`;
552	                if (!blockedSet.has(key)) {
553	                    const adjacentTile = game.board[pos.row][pos.col];
554	                    if (
555	                        isBlocked(adjacentTile) ||
556	                        isBlockedWithLife(adjacentTile) ||
557	                        isBlockedMovable(adjacentTile) ||
558	                        isBlockedWithMergeCount(adjacentTile)
559	                    ) {
560	                        blockedSet.add(key);
561	                        result.push(pos);
562	                    }
563	                }
564	            }
565	        }
566	    }
567	
568	    return result;
569	}
570	
571	/**
572	 * Execute the board-level swap logic (pure: no DOM, no animation).
573	 * Mutates game.board and game state flags.
574	 * @returns {{ valid: boolean, hasMatch: boolean, hasFreeSwap: boolean, hasTeleport: boolean,
575	 *             isSwapPowerUp: boolean, isTeleportPowerUp: boolean, allowNonMatchingSwap: boolean }}
576	 *   An invalid or disallowed swap is indicated by `valid: false`.
577	 */
578	export function executeSwap(game, row1, col1, row2, col2) {
579	    const tile1 = game.board[row1][col1];
580	
581	    const isHorizontalSwap = row1 === row2;
582	    const isVerticalSwap = col1 === col2;
583	
584	    const isFreeSwap1 = (isTileFreeSwapTile(tile1) || isTileStickyFreeSwapTile(tile1)) && !tile1.hasBeenSwapped;
585	    const isDirectionalFreeSwap1 =
586	        !tile1.hasBeenSwapped &&
587	        ((isTileFreeSwapHorizontalTile(tile1) && isHorizontalSwap) ||
588	            (isTileFreeSwapVerticalTile(tile1) && isVerticalSwap));
589	    const hasFreeSwap = isFreeSwap1 || isDirectionalFreeSwap1;
590	    const hasTeleport = (isTileTeleportTile(tile1) || isWildTeleportTile(tile1)) && !tile1.hasBeenSwapped;
591	    const isSwapPowerUp = game.activePowerUp === "swap";
592	    const isTeleportPowerUp = game.activePowerUp === "teleport";
593	    const allowNonMatchingSwap = game.allowNonMatchingSwaps === true;
594	
595	    // Perform the board swap
596	    const temp = game.board[row1][col1];
597	    game.board[row1][col1] = game.board[row2][col2];
598	    game.board[row2][col2] = temp;
599	
600	    game.lastSwapPosition = { row: row2, col: col2, movedFrom: { row: row1, col: col1 } };
601	    game.isUserSwap = true;
602	
603	    const hasMatch = game.hasMatchesForSwap(row1, col1, row2, col2);
604	
605	    if (hasMatch || isSwapPowerUp || isTeleportPowerUp || hasFreeSwap || hasTeleport || allowNonMatchingSwap) {
606	        // Count the move
607	        if (!isSwapPowerUp && !isTeleportPowerUp && !hasFreeSwap && !hasTeleport) {
608	            game.movesUsed++;
609	        }
610	
611	        game.shouldDecrementCursedTimers = true;
612	        game.cursedTileCreatedThisTurn = {};
613	
614	        // Mark free swap tile as used (tile1 is now at row2/col2 after swap)
615	        if (hasFreeSwap) {
616	            game.board[row2][col2].hasBeenSwapped = true;
617	        }
618	        if (hasTeleport) {
619	            game.board[row2][col2].hasBeenSwapped = true;
620	        }
621	
622	        return {
623	            valid: true,
624	            hasMatch,
625	            hasFreeSwap,
626	            hasTeleport,
627	            isSwapPowerUp,
628	            isTeleportPowerUp,
629	            allowNonMatchingSwap,
630	        };
631	    } else {
632	        // Revert the swap
633	        game.board[row2][col2] = game.board[row1][col1];
634	        game.board[row1][col1] = temp;
635	        game.lastSwapPosition = null;
636	        game.isUserSwap = false;
637	        return {
638	            valid: false,
639	            hasMatch: false,
640	            hasFreeSwap,
641	            hasTeleport,
642	            isSwapPowerUp,
643	            isTeleportPowerUp,
644	            allowNonMatchingSwap,
645	        };
646	    }
647	}
