649	export function trySwap(game, row1, col1, row2, col2) {
650	    if (!game.gameActive) return;
651	
652	    // Tutorial validation - only allow defined swaps during tutorial
653	    if (isTutorialActive(game)) {
654	        if (!isValidTutorialSwap(game, row1, col1, row2, col2)) {
655	            game.animateRevert(row1, col1, row2, col2);
656	            return false;
657	        }
658	    }
659	
660	    // Prevent swapping blocked/blocked-with-life tiles unless swap power-up on simple (non-rectangular) blocked
661	    const isSwapPowerUp = game.activePowerUp === "swap";
662	    const t1 = game.board[row1][col1];
663	    const t2 = game.board[row2][col2];
664	    const t1SimpleBlocked = isBlocked(t1) && !isRectangularBlocked(t1);
665	    const t2SimpleBlocked = isBlocked(t2) && !isRectangularBlocked(t2);
666	    if (isBlockedWithLife(t1) || isBlockedWithLife(t2)) return;
667	    if (isBlocked(t1) && !t1SimpleBlocked) return;
668	    if (isBlocked(t2) && !t2SimpleBlocked) return;
669	    if ((t1SimpleBlocked || t2SimpleBlocked) && !isSwapPowerUp) return;
670	
671	    const isAdjacentSwap = areAdjacent(row1, col1, row2, col2);
672	    const allowExtendedFreeSwap = !isAdjacentSwap && isExtendedFreeSwapAllowed(game, row1, col1, row2, col2);
673	    const allowTeleportSwap = !isAdjacentSwap && isTeleportSwapAllowed(game, row1, col1, row2, col2);
674	    const isPowerUpSwap = !isAdjacentSwap && game.activePowerUp === "teleport";
675	
676	    if (!isAdjacentSwap && !allowExtendedFreeSwap && !allowTeleportSwap && !isPowerUpSwap) {
677	        return false;
