681	    if (game.animating) {
682	        game.interruptCascade = true;
683	        game.pendingSwap = {
684	            row1,
685	            col1,
686	            row2,
687	            col2,
688	            tile1: game.board[row1][col1],
689	            tile2: game.board[row2][col2],
