/* Merge Preview Styles - for hints */
.hint-merge-preview,
.merge-preview {
    /* filter: brightness(0.7); */
    /* outline: 2px dashed rgba(255, 255, 255, 1); */
    outline: 2px dashed rgba(0, 0, 0, 0.4);
    outline-offset: -4px;
    z-index: 100;
    opacity: 1 !important;
    filter: none !important;
}

/* Unblock Preview - blocked tiles that will be removed */
.unblock-preview {
    outline: 2px dashed rgba(255, 100, 100, 0.8);
    outline-offset: -4px;
    z-index: 100;
    opacity: 1 !important;
    filter: none !important;
}

/* Formation Power-Up Reward Animation */
.formation-powerup-animation {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    z-index: 1000;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 8px;
    animation: formationPowerUpFloat 2s ease-out forwards;
    pointer-events: none;
}

.formation-powerup-headline {
    animation: formationPowerUpPop 0.3s ease-out;
    /* filter: drop-shadow(0 0 20px rgba(255, 215, 0, 0.8)); */

